using System;using System.Collections.Generic;
public class Program{static int Max(List<int[]>e){e.Sort((a,b)=>a[0]==b[0]?b[1]-a[1]:a[0]-b[0]);var tails=new List<int>();foreach(var p in e){int i=tails.BinarySearch(p[1]);if(i<0)i=~i;if(i==tails.Count)tails.Add(p[1]);else tails[i]=p[1];}return tails.Count;}public static void Main(){string[]d=Console.In.ReadToEnd().Split((char[])null,StringSplitOptions.RemoveEmptyEntries);if(d.Length==0)return;int idx=0,t=int.Parse(d[idx++]);var outv=new List<string>();for(int tc=0;tc<t;tc++){int n=int.Parse(d[idx++]);var e=new List<int[]>();for(int i=0;i<n;i++)e.Add(new[]{int.Parse(d[idx++]),int.Parse(d[idx++])});outv.Add(Max(e).ToString());}Console.Write(string.Join("\n\n",outv));}}
